import{_ as r,C as c,o as t,c as i,a3 as a,b as l,w as o,a as s,E as h,a4 as d}from"./chunks/framework.aYYe0dfI.js";const b=JSON.parse('{"title":"Namespace clore::net::anthropic","description":"The clore::net::anthropic namespace provides a set of asynchronous interfaces for interacting with Anthropic’s language model and completion APIs. Its primary functions include overloads of call_llm_async, which accept model identifiers, prompts, system prompts, and configuration parameters; call_completion_async, which takes an integer handle and an event loop to finalize a prior request; and the template function call_structured_async<T>, designed to return a typed, structured response from the API. All asynchronous operations are scheduled on a kota::event_loop and return an integer handle that callers must retain for later completion polling. The namespace abstracts the details of HTTP communication and event‑loop integration, letting higher‑level code initiate non‑blocking Anthropic calls without managing network or concurrency primitives directly. Its architectural role is to serve as a low‑level network client that bridges the Anthropic service with the library’s event‑driven runtime, ensuring that string arguments remain valid until an operation completes and that the event loop remains active throughout the async invocation.","frontmatter":{"title":"Namespace clore::net::anthropic","description":"The clore::net::anthropic namespace provides a set of asynchronous interfaces for interacting with Anthropic’s language model and completion APIs. Its primary functions include overloads of call_llm_async, which accept model identifiers, prompts, system prompts, and configuration parameters; call_completion_async, which takes an integer handle and an event loop to finalize a prior request; and the template function call_structured_async<T>, designed to return a typed, structured response from the API. All asynchronous operations are scheduled on a kota::event_loop and return an integer handle that callers must retain for later completion polling. The namespace abstracts the details of HTTP communication and event‑loop integration, letting higher‑level code initiate non‑blocking Anthropic calls without managing network or concurrency primitives directly. Its architectural role is to serve as a low‑level network client that bridges the Anthropic service with the library’s event‑driven runtime, ensuring that string arguments remain valid until an operation completes and that the event loop remains active throughout the async invocation.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/namespaces/clore/net/anthropic/index.md","filePath":"en/clore/namespaces/clore/net/anthropic/index.md"}'),p={name:"clore/namespaces/clore/net/anthropic/index.md"};function u(m,e,g,f,y,_){const n=c("Mermaid");return t(),i("div",null,[e[1]||(e[1]=a('<h1 id="namespace-clore-net-anthropic" tabindex="-1">Namespace <code>clore::net::anthropic</code> <a class="header-anchor" href="#namespace-clore-net-anthropic" aria-label="Permalink to &quot;Namespace `clore::net::anthropic`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>clore::net::anthropic</code> namespace provides a set of asynchronous interfaces for interacting with Anthropic’s language model and completion <code>APIs</code>. Its primary functions include overloads of <code>call_llm_async</code>, which accept model identifiers, prompts, system prompts, and configuration parameters; <code>call_completion_async</code>, which takes an integer handle and an event loop to finalize a prior request; and the template function <code>call_structured_async&lt;T&gt;</code>, designed to return a typed, structured response from the API. All asynchronous operations are scheduled on a <code>kota::event_loop</code> and return an integer handle that callers must retain for later completion polling. The namespace abstracts the details of HTTP communication and event‑loop integration, letting higher‑level code initiate non‑blocking Anthropic calls without managing network or concurrency primitives directly. Its architectural role is to serve as a low‑level network client that bridges the Anthropic service with the library’s event‑driven runtime, ensuring that string arguments remain valid until an operation completes and that the event loop remains active throughout the async invocation.</p><h2 id="diagram" tabindex="-1">Diagram <a class="header-anchor" href="#diagram" aria-label="Permalink to &quot;Diagram&quot;">​</a></h2>',4)),(t(),l(d,null,{default:o(()=>[h(n,{id:"mermaid-12",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20NS%5B%22anthropic%22%5D%0A%20%20%20%20NSC0%5B%22detail%22%5D%0A%20%20%20%20NS%20--%3E%20NSC0%0A%20%20%20%20NSC1%5B%22protocol%22%5D%0A%20%20%20%20NS%20--%3E%20NSC1%0A%20%20%20%20NSC2%5B%22schema%22%5D%0A%20%20%20%20NS%20--%3E%20NSC2%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[s(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<h2 id="subnamespaces" tabindex="-1">Subnamespaces <a class="header-anchor" href="#subnamespaces" aria-label="Permalink to &quot;Subnamespaces&quot;">​</a></h2><ul><li><a href="./detail/"><code>clore::net::anthropic::detail</code></a></li><li><a href="./protocol/"><code>clore::net::anthropic::protocol</code></a></li><li><a href="./schema/"><code>clore::net::anthropic::schema</code></a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-anthropic-call-completion-async" tabindex="-1"><code>clore::net::anthropic::call_completion_async</code> <a class="header-anchor" href="#clore-net-anthropic-call-completion-async" aria-label="Permalink to &quot;`clore::net::anthropic::call_completion_async`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:722</code></p><p>Definition: <code>network/anthropic.cppm:764</code></p><p>Implementation: <a href="./../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p>The function <code>clore::net::anthropic::call_completion_async</code> initiates an asynchronous call to the Anthropic completion API. It accepts an integer parameter that identifies the request or configures the call, and a reference to a <code>kota::event_loop</code> on which the asynchronous operation is scheduled. The function returns an integer value that represents the status of the operation or a handle to the pending request. Callers must ensure the provided event loop remains live for the duration of the asynchronous work; the meaning of the integer argument and the exact contract for the returned value are defined by the component&#39;s public interface.</p><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to start an async completion call and obtain a task that can be awaited.</li><li>Typically called from event-loop-driven code that needs to query an AI model.</li></ul><h3 id="clore-net-anthropic-call-llm-async" tabindex="-1"><code>clore::net::anthropic::call_llm_async</code> <a class="header-anchor" href="#clore-net-anthropic-call-llm-async" aria-label="Permalink to &quot;`clore::net::anthropic::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:732</code></p><p>Definition: <code>network/anthropic.cppm:782</code></p><p>Implementation: <a href="./../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p>Initiates an asynchronous request to the Anthropic language model service, scheduling the operation on the provided <code>kota::event_loop</code>. The caller supplies three <code>std::string_view</code> parameters—typically a model identifier, a user message, and an API credential—and a reference to an event loop that will drive the asynchronous completion. The function returns an <code>int</code> handle that uniquely identifies this request.</p><p>The caller should retain the returned <code>int</code> to later retrieve the outcome via <code>call_completion_async</code>. All string arguments must remain valid until the operation completes, as the asynchronous mechanism may refer to them without copying. The <code>kota::event_loop</code> must be active and running for the request to progress.</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Await the returned task to obtain the LLM response.</li><li>Call from an async context with an active <code>kota::event_loop</code>.</li></ul><h3 id="clore-net-anthropic-call-llm-async-1" tabindex="-1"><code>clore::net::anthropic::call_llm_async</code> <a class="header-anchor" href="#clore-net-anthropic-call-llm-async-1" aria-label="Permalink to &quot;`clore::net::anthropic::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:726</code></p><p>Definition: <code>network/anthropic.cppm:771</code></p><p>Implementation: <a href="./../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p>The function <code>clore::net::anthropic::call_llm_async</code> initiates an asynchronous request to the Anthropic large language model API. The caller provides two <code>std::string_view</code> arguments (likely identifying the model and the system prompt or a message), an <code>int</code> argument (typically a timeout, retry count, or a configuration identifier), and a reference to a <code>kota::event_loop</code> that will drive the asynchronous operation. The returned <code>int</code> value is an opaque handle that the caller must retain for subsequent use with functions such as <code>clore::net::anthropic::call_completion_async</code> to poll or finalise the result. The caller is responsible for ensuring the <code>kota::event_loop</code> remains active for the duration of the asynchronous call; otherwise the operation may never complete.</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called by other async functions to obtain an LLM response.</li><li>Used with <code>kota::event_loop</code> for asynchronous execution.</li></ul><h3 id="clore-net-anthropic-call-structured-async" tabindex="-1"><code>clore::net::anthropic::call_structured_async</code> <a class="header-anchor" href="#clore-net-anthropic-call-structured-async" aria-label="Permalink to &quot;`clore::net::anthropic::call_structured_async`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:739</code></p><p>Definition: <code>network/anthropic.cppm:794</code></p><p>Implementation: <a href="./../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p>The template function <code>clore::net::anthropic::call_structured_async&lt;T&gt;</code> initiates an asynchronous request to the Anthropic API to obtain a structured (typed) response. It accepts three <code>std::string_view</code> arguments — likely a system prompt, user prompt, and a schema or model identifier — and a <code>kota::event_loop &amp;</code> on which the asynchronous completion will be dispatched. The function returns an <code>int</code> that serves as a handle for the pending operation; the caller can use this handle to later retrieve the parsed result of type <code>T</code> once the operation completes. The caller is responsible for ensuring the event loop is running and that the provided strings remain valid for the duration of the asynchronous call.</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to perform structured async LLM interactions with Anthropic</li><li>Acts as a type-safe wrapper binding <code>detail::Protocol</code></li><li>Used in coroutine contexts where <code>co_await</code> is applied</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore::net</a></li><li><a href="./detail/">Namespace clore::net::anthropic::detail</a></li><li><a href="./protocol/">Namespace clore::net::anthropic::protocol</a></li><li><a href="./schema/">Namespace clore::net::anthropic::schema</a></li></ul>',34))])}const w=r(p,[["render",u]]);export{b as __pageData,w as default};
